export const HSK4_EXCEL_ITEM_COUNT = HSK4_EXCEL_ROWS.length;

export const HSK4_EXCEL_VI_MEANINGS: Record<string, string> = Object.fromEntries(
  HSK4_EXCEL_ROWS.map((row) => [row.hanzi, row.meaningVi]),
);

export function createExcelCourseItems(): VocabItem[] {
  return HSK4_EXCEL_ROWS.map((row) => {
    const type = "New Word";
    return {
      id: stableId(row.book, row.lesson, row.hanzi, type),
      book: row.book,
      lesson: row.lesson,
      lessonTitle: row.lessonTitle,
      order: row.order,
      hanzi: row.hanzi,
      pinyin: row.pinyin,
      meaningVi: row.meaningVi,
      meaningEn: "",
      partOfSpeech: row.partOfSpeech,
      exampleHan: row.exampleHan,
      examplePinyin: "",
      exampleVi: row.exampleVi,
      source: row.section ? `${HSK4_EXCEL_SOURCE} - ${row.section}` : HSK4_EXCEL_SOURCE,
      note: row.sourceUrl ? `${HSK4_EXCEL_NOTE} Source: ${row.sourceUrl}` : HSK4_EXCEL_NOTE,
      type,
    };
  });
}

function stableId(book: BookCode, lesson: number, hanzi: string, type: string): string {
  const normalized = `${book}-${lesson}-${hanzi}-${type}`.replace(/\s+/g, "-");
  return encodeURIComponent(normalized);
}
